        { const __m256d wr = LD(&W_re[13*me+m]);
          const __m256d wi = LD(&W_im[13*me+m]);
          const __m256d tr = x3_re;
          x3_re = _mm256_fmadd_pd(x3_re,wr,_mm256_mul_pd(x3_im,wi));
          x3_im = _mm256_fmsub_pd(x3_im,wr,_mm256_mul_pd(tr,wi)); }

